echo "=== sunshine_state.json (keys only) ==="; python3 -c "
import json
d=json.load(open('$HOME/.config/sunshine/sunshine_state.json'))
def walk(o,p=''):
    if isinstance(o,dict):
        for k,v in o.items():
            if isinstance(v,(dict,list)): walk(v,p+'/'+k)
            else: print(f'{p}/{k}: {type(v).__name__} len={len(str(v))}')
    elif isinstance(o,list):
        for i,v in enumerate(o): walk(v,p+f'[{i}]')
walk(d)
" 2>/dev/null || head -c 400 ~/.config/sunshine/sunshine_state.json
